import React, { useRef } from 'react';
import { Breadcrumb, Card, message } from 'antd';
import { useIntl, useModel } from '@umijs/max';
import { t } from '@/global';
import ProForm, { ProFormDigit, ProFormInstance, ProFormSwitch, ProFormText } from '@ant-design/pro-form';
import { getIdChangeSupport, getSessionExpireTime, updateIdChangeSupport, updateSessionExpireTime, updateSettings } from '@/services/api';
import { PageContainer } from '@ant-design/pro-layout';

const SECOND_OF_DAY = 3600 * 24;

type FormData = {
    session_exp_day: number;
    audit_retention_days: number;
    id_change_support: boolean;
    idp_allow_local_password_login: boolean;
    disable_new_device: boolean;
    access_require_login: boolean;
    only_admin_access_unassigned: boolean;
    allow_non_admin_see_other_group: boolean;
    only_admin_access_logs: boolean;
    disable_read_accessible: boolean;
    new_user_enforce_tfa: boolean;
    sync_device_name_with_hostname: boolean;
    tfa_issuer: string;
}

const App: React.FC = () => {
    const { initialState, setInitialState } = useModel('@@initialState');
    const { loading } = initialState!;
    const { settings: settingsList } = initialState!;
    const formRef = useRef<ProFormInstance<FormData>>();
    const intl = useIntl();

    const plain = (text: string, defaultMessage = '') => t(`pages.Settings.Others.${text}`, true, defaultMessage || text, intl) as string;

    const getFormData = async () => {
        const session_exp_second = await getSessionExpireTime();
        const id_change_support = await getIdChangeSupport();
        const idp_allow_local_password_login_value = settingsList?.find((entry) => entry.key === 'IDP_ALLOW_LOCAL_PASSWORD_LOGIN')?.value;
        const idp_allow_local_password_login = idp_allow_local_password_login_value === 'TRUE' || idp_allow_local_password_login_value === 'Y';
        const disable_new_device_value = settingsList?.find((entry) => entry.key === 'DISABLE_NEW_DEVICE')?.value;
        const disable_new_device = disable_new_device_value === 'TRUE' || disable_new_device_value === 'Y';
        const access_require_login_value = settingsList?.find((entry) => entry.key === 'ACCESS_REQUIRE_LOGIN')?.value;
        const access_require_login = (initialState?.license?.max_conns || 0) > 0 || access_require_login_value === 'TRUE' || access_require_login_value === 'Y';
        const only_admin_access_unassigned_value = settingsList?.find((entry) => entry.key === 'ONLY_ADMIN_ACCESS_UNASSIGNED')?.value;
        const only_admin_access_unassigned = only_admin_access_unassigned_value === 'TRUE' || only_admin_access_unassigned_value === 'Y';
        const allow_non_admin_see_other_group_value = settingsList?.find((entry) => entry.key === 'ALLOW_NON_ADMIN_SEE_OTHER_GROUP')?.value;
        const allow_non_admin_see_other_group = allow_non_admin_see_other_group_value === 'TRUE' || allow_non_admin_see_other_group_value === 'Y';
        const only_admin_access_logs_value = settingsList?.find((entry) => entry.key === 'ONLY_ADMIN_ACCESS_LOGS')?.value;
        const only_admin_access_logs = only_admin_access_logs_value === 'TRUE' || only_admin_access_logs_value === 'Y';
        const disable_read_accessible_value = settingsList?.find((entry) => entry.key === 'DISABLE_READ_ACCESSIBLE')?.value;
        const disable_read_accessible = disable_read_accessible_value === 'TRUE' || disable_read_accessible_value === 'Y';
        const new_user_enforce_tfa_value = settingsList?.find((entry) => entry.key === 'NEW_USER_ENFORCE_TFA')?.value;
        const new_user_enforce_tfa = new_user_enforce_tfa_value === 'TRUE' || new_user_enforce_tfa_value === 'Y';
        const sync_device_name_with_hostname_value = settingsList?.find((entry) => entry.key === 'SYNC_DEVICE_NAME_WITH_HOSTNAME')?.value;
        const sync_device_name_with_hostname = sync_device_name_with_hostname_value === 'TRUE' || sync_device_name_with_hostname_value === 'Y';
        const tfa_issuer = settingsList?.find((entry) => entry.key === 'TFA_ISSUER')?.value || '';
        const audit_retention_days_value = settingsList?.find((entry) => entry.key === 'AUDIT_RETENTION_DAYS')?.value;
        let audit_retention_days = 0;
        try {
            if (audit_retention_days_value) {
                audit_retention_days = parseInt(audit_retention_days_value);
            }
        } catch (error) {
            console.error(error);
        }

        const data: FormData = {
            session_exp_day: session_exp_second / SECOND_OF_DAY,
            audit_retention_days,
            id_change_support,
            idp_allow_local_password_login,
            disable_new_device,
            access_require_login,
            only_admin_access_unassigned,
            allow_non_admin_see_other_group,
            only_admin_access_logs,
            disable_read_accessible,
            new_user_enforce_tfa,
            sync_device_name_with_hostname,
            tfa_issuer,
        };
        return data;
    }

    const updateSettingsModel = async (keyValueList: { key: string, value: string }[]) => {
        const settings = settingsList || [];
        keyValueList.forEach(({ key, value }) => {
            const i = settings.findIndex((entry) => entry.key === key);
            if (i >= 0) settings[i].value = value;
            else settings.push({ key, value });
        });
        await setInitialState((s) => ({
            ...s,
            settings,
        }));
    };

    const handleSubmit = async (data: FormData) => {
        try {
            await updateSessionExpireTime(data.session_exp_day * SECOND_OF_DAY);
            await updateIdChangeSupport(data.id_change_support);
            const idp_allow_local_password_login = data.idp_allow_local_password_login ? 'TRUE' : 'FALSE';
            const disable_new_device = data.disable_new_device ? 'TRUE' : 'FALSE';
            const access_require_login = data.access_require_login ? 'TRUE' : 'FALSE';
            const only_admin_access_unassigned = data.only_admin_access_unassigned ? 'TRUE' : 'FALSE';
            const allow_non_admin_see_other_group = data.allow_non_admin_see_other_group ? 'TRUE' : 'FALSE';
            const only_admin_access_logs = data.only_admin_access_logs ? 'TRUE' : 'FALSE';
            const disable_read_accessible = data.disable_read_accessible ? 'TRUE' : 'FALSE';
            const new_user_enforce_tfa = data.new_user_enforce_tfa ? 'TRUE' : 'FALSE';
            const sync_device_name_with_hostname = data.sync_device_name_with_hostname ? 'TRUE' : 'FALSE';
            const audit_retention_days = data.audit_retention_days.toString();
            const tfa_issuer = (data.tfa_issuer || '').trim();
            await updateSettings({
                IDP_ALLOW_LOCAL_PASSWORD_LOGIN: idp_allow_local_password_login,
                DISABLE_NEW_DEVICE: disable_new_device,
                ACCESS_REQUIRE_LOGIN: access_require_login,
                ONLY_ADMIN_ACCESS_UNASSIGNED: only_admin_access_unassigned,
                ALLOW_NON_ADMIN_SEE_OTHER_GROUP: allow_non_admin_see_other_group,
                ONLY_ADMIN_ACCESS_LOGS: only_admin_access_logs,
                AUDIT_RETENTION_DAYS: audit_retention_days,
                DISABLE_READ_ACCESSIBLE: disable_read_accessible,
                NEW_USER_ENFORCE_TFA: new_user_enforce_tfa,
                SYNC_DEVICE_NAME_WITH_HOSTNAME: sync_device_name_with_hostname,
                TFA_ISSUER: tfa_issuer,
            });
            await updateSettingsModel([
                { key: 'IDP_ALLOW_LOCAL_PASSWORD_LOGIN', value: idp_allow_local_password_login },
                { key: 'DISABLE_NEW_DEVICE', value: disable_new_device },
                { key: 'ACCESS_REQUIRE_LOGIN', value: access_require_login },
                { key: 'ONLY_ADMIN_ACCESS_UNASSIGNED', value: only_admin_access_unassigned },
                { key: 'ALLOW_NON_ADMIN_SEE_OTHER_GROUP', value: allow_non_admin_see_other_group },
                { key: 'ONLY_ADMIN_ACCESS_LOGS', value: only_admin_access_logs },
                { key: 'AUDIT_RETENTION_DAYS', value: audit_retention_days },
                { key: 'DISABLE_READ_ACCESSIBLE', value: disable_read_accessible },
                { key: 'NEW_USER_ENFORCE_TFA', value: new_user_enforce_tfa },
                { key: 'SYNC_DEVICE_NAME_WITH_HOSTNAME', value: sync_device_name_with_hostname },
                { key: 'TFA_ISSUER', value: tfa_issuer },
            ]);
            message.success("Submit successfully.");
        } catch (error) {
            message.error('' + error);
        }
    };

    const getSessionExpireTimeComponent = () => {
        return <ProFormDigit
            label={plain("Session expiration time (Days)")}
            name="session_exp_day"
            rules={[
                {
                    required: true,
                },
            ]}
            min={1}
            max={365}
            width={80}
            fieldProps={{ precision: 0 }}
        />
    }

    const getAuditRetentionDaysComponent = () => {
        return <ProFormDigit
            label={t("audit_retention_days")}
            name="audit_retention_days"
            rules={[
                {
                    required: true,
                },
            ]}
            min={0}
            max={9999}
            width={80}
            fieldProps={{ precision: 0 }}
            tooltip={t("audit_retention_days_tip")}
        />
    }

    const getIdChangeSupportComponent = () => {
        return <ProFormSwitch name={["id_change_support"]} label={plain("Allow change ID")} />
    }

    const getIdpAllowLocalPasswordLoginComponent = () => {
        return (
            <ProFormSwitch
                name={["idp_allow_local_password_login"]}
                label={plain(
                    "idp_allow_local_password_login",
                    "Allow IdP (OIDC) users to log in with local password",
                )}
            />
        );
    }

    const getSyncDeviceNameWithHostnameComponent = () => {
        return (
            <ProFormSwitch
                name={["sync_device_name_with_hostname"]}
                label={t("sync_device_name_with_hostname")}
                tooltip={t(
                    "allow_device_name_change_tip",
                )}
            />
        );
    }

    const getDisableNewDeviceComponent = () => {
        return <ProFormSwitch name={["disable_new_device"]} label={plain("Disable new devices")} />
    }

    const getAccessRequireLoginComponent = () => {
        const always_required = (initialState?.license?.max_conns || 0) > 0;
        return <ProFormSwitch disabled={always_required} tooltip={always_required ? "Always required for license with limited concurrent connections" : ""} name={["access_require_login"]} label={plain("Login is required on the control end before access")} />
    }

    const getOnlyAdminAccessUnassignedComponent = () => {
        return <ProFormSwitch name={["only_admin_access_unassigned"]} label={plain("Only admin can access unassigned devices")} />
    }

    const getAllowNonAdminSeeOtherGroupComponent = () => {
        return <ProFormSwitch
            name={["allow_non_admin_see_other_group"]}
            label={plain("Allow non-admin to share address books to other groups")} />
    }

    const getOnlyAdminAccessLogsComponent = () => {
        return <ProFormSwitch
            name={["only_admin_access_logs"]}
            label={plain("Only admin can access logs")}
            tooltip={plain("only_admin_access_logs_tip", "When the option is on, non-admin can't access connection logs, file logs, or alarm logs.")} />
    }

    const getDisableReadAccessibleComponent = () => {
        return <ProFormSwitch name={["disable_read_accessible"]} label={t("disable_read_accessible")} tooltip={t("disable_read_accessible_tip")} />
    }

    const getNewUserEnforceTfaComponent = () => {
        return <ProFormSwitch name={["new_user_enforce_tfa"]} label={t("new_user_enforce_tfa")} tooltip={t("new_user_enforce_tfa_tip")} />
    }

    const getTfaIssuerComponent = () => {
        return <ProFormText
            name="tfa_issuer"
            label={plain("2FA Issuer Name")}
            tooltip={plain("tfa_issuer_tip", "Custom name displayed in authenticator apps when scanning 2FA QR code, shown as \"<name> Login\". Default is RustDesk.")}
            width="md"
            placeholder="RustDesk"
            fieldProps={{ autoComplete: 'off' }}
        />
    }

    return (
        <PageContainer
            breadcrumbRender={() => (
                <Breadcrumb items={[
                    { title: t('menu.Settings', true) },
                    { title: t('menu.Settings.Others', true) },
                ]} />
            )}
        >
            {loading ? null : (
                <Card>
                    <ProForm
                        formRef={formRef}
                        layout="horizontal"
                        hideRequiredMark
                        onFinish={handleSubmit}
                        labelCol={{ span: 8, offset: 0 }}
                        labelAlign="left"
                        labelWrap={true}
                        colon={false}
                        request={async () => {
                            try {
                                let info = await getFormData();
                                if (info) {
                                    return info;
                                }
                            } catch (error) {
                                message.error("Request data failed: " + error);
                            }
                            return Promise.reject();
                        }}
                    >
                        {getSessionExpireTimeComponent()}
                        {getAuditRetentionDaysComponent()}
                        {getIdChangeSupportComponent()}
                        {getIdpAllowLocalPasswordLoginComponent()}
                        {getSyncDeviceNameWithHostnameComponent()}
                        {getDisableNewDeviceComponent()}
                        {getAccessRequireLoginComponent()}
                        {getOnlyAdminAccessUnassignedComponent()}
                        {getAllowNonAdminSeeOtherGroupComponent()}
                        {getOnlyAdminAccessLogsComponent()}
                        {getDisableReadAccessibleComponent()}
                        {getNewUserEnforceTfaComponent()}
                        {getTfaIssuerComponent()}
                    </ProForm>
                </Card>
            )}
        </PageContainer>
    );
};

export default App;
